def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    for i, capacity in enumerate(bins):
        if capacity <= 0:
            continue
        ratio = item / capacity
        if ratio > 1:
            continue
        score = 0
        series_sum = 0
        for power in range(1, 20):
            base_factor = (0.9 + 0.15 * ((power % 5) / 5))
            if power % 4 == 0:
                base_factor *= 1.3
            elif power % 3 == 0:
                base_factor *= 0.85
            decay = 1 / (power ** 1.5)
            term = base_factor * decay * (ratio ** power)
            series_sum += term
            if power % 7 == 0:
                series_sum += 0.03 * np.sin(power * np.pi / 10)
        score = series_sum
        remaining = capacity - item
        if remaining < 0.02 * capacity:
            score *= 3.2
        elif remaining < 0.07 * capacity:
            score *= 2.1
        elif remaining < 0.15 * capacity:
            score *= 1.3
        else:
            score *= 0.65
        mods = [int(capacity) % d == 0 for d in (2,3,5,7,11)]
        mod_sum = sum(mods)
        if mod_sum >= 4:
            score -= 0.2 * (capacity / 12)
        elif mod_sum == 3:
            score -= 0.15 * (capacity / 18)
        elif mod_sum == 2:
            score -= 0.1 * (capacity / 25)
        elif mod_sum == 1:
            score -= 0.05 * (capacity / 40)
        else:
            score -= 0.02 * (capacity / 60)
        penalty = 0
        for k in range(1, 10):
            diff = abs(capacity - item * k)
            threshold = 0.02 * capacity * max(1, k/2)
            if diff < threshold:
                penalty += 0.3 * k
            elif diff < 3 * threshold:
                penalty += 0.15 * k
            else:
                penalty -= 0.1 * k**0.5
            if diff < threshold and (k % 2 == 0):
                penalty += 0.1 * (k/2)
        score += penalty
        for m in range(1, 6):
            val = capacity / m
            diff = abs(val - item)
            tolerance = 0.03 * val
            if diff < tolerance:
                factor = 1 + 0.07 * m
                if m % 2 == 0:
                    factor += 0.02
                score *= factor
        if capacity > 100:
            extra_factor = np.log(capacity/50) / 10
            if capacity % 13 == 0:
                extra_factor *= 1.5
            score *= (1 + extra_factor)
        if score < 0:
            score = 0
        if score > 2:
            score = 2
        priorities[i] = score
    return priorities
